UPDATE public.courses SET detail_content = '{"longDescription":"Il corso si concentra sull''apprendimento del linguaggio di programmazione LUA così come sulla modellazione in 3D degli scenari. Il corso insegna le basi della programmazione, utili come punto di partenza per gli studenti che intendono diventare programmatori professionisti. Il corso sviluppa il pensiero creativo e spaziale attraverso la modellazione di diversi oggetti in 3D. Gli studenti creeranno i loro giochi e svilupperanno il pensiero progettuale (design thinking).","age":"8+ anni","level":"Principiante","duration":"32 lezioni","tags":["Roblox","LUA","Programmazione","Game design"],"topics":["Conoscenza di base del linguaggio LUA","Creazione di giochi su Roblox Studio","Modellazione 3D","Progettazione su livelli","Fondamenti di animazione, effetti sonori e visivi"],"projectExamples":[{"title":"Torre nell''Inferno"},{"title":"Gioco di corse"},{"title":"Gioco d''avventura"}],"modules":[{"title":"Modulo 1: Gioco ''Salva il mondo''!","lessons":["1. Introduzione a Roblox! Le basi della creazione di giochi. Interfaccia di base di Roblox Studio.","2. Strumenti avanzati di modifica del terreno. Esecuzione di una mappa già pronta.","3. Creare modelli 3D utilizzando blocchi e altri oggetti di base. Modificare colori e materiali.","4. Nozioni di base di programmazione. Impariamo a conoscere le variabili e a modificarne i valori."],"result":"Abbiamo imparato a creare un gioco in Roblox Studio partendo da zero. Abbiamo studiato i concetti di base del game design, della modellazione 3D e della programmazione."},{"title":"Modulo 2: Torre nell''Inferno","lessons":["5. Iniziare lo sviluppo di un gioco famoso: ''Torre dell''Inferno''. Studio di strumenti avanzati di modellazione 3D.","6. Le basi della programmazione. Funzioni. Conoscere le funzioni nel linguaggio LUA.","7. Imparare la fisica in Roblox Studio. Uso dei motori e della fisica per creare ostacoli.","8. Le basi della programmazione. Operatore condizionale. Imparare a modificare la salute del giocatore."],"result":"Abbiamo imparato a conoscere il sistema di fisica di Roblox Studio. Abbiamo imparato le basi della programmazione LUA."},{"title":"Modulo 3: Torre nell''Inferno - Espandere le funzionalità","lessons":["9. Le basi della programmazione. I cicli. Uso degli script per creare nuovi ostacoli.","10. Creare oggetti in movimento. Studio dell''animazione degli oggetti.","11. Implementare l''interazione con gli oggetti. Creazione di oggetti interattivi.","12. Creazione di checkpoint. Creazione di boost e di un percorso parkour a tempo limitato."],"result":"Abbiamo continuato a imparare di più sulla programmazione. Abbiamo completato il progetto ''Torre dell''Inferno'' e lo abbiamo pubblicato su Internet!"},{"title":"Modulo 4: Il gioco di corse","lessons":["13. Introduzione alle basi del game design. Lavoro avanzato sulle ambientazioni. Creazione di piste da corsa personalizzate.","14. Le basi della scrittura di script nel linguaggio LUA. Apprendimento delle funzioni. Modellazione e impostazione del movimento dell''auto.","15. Imparare a creare effetti visivi. Lavorare con l''interfaccia utente e il linguaggio LUA.","16. Finalizzazione del progetto. Aggiunta di attività per i giocatori: una gara a tempo."],"result":"Abbiamo approfondito la nostra conoscenza della programmazione LUA. Abbiamo creato il nostro gioco con una pista da corsa e lo abbiamo pubblicato online!"},{"title":"Modulo 5: Gioco d''avventura - Sviluppo di squadra. NPC","lessons":["17. Imparare lo sviluppo in gruppo. Lavorare in gruppo per creare un nuovo mondo.","18. Personaggi non giocanti. Creazione e personalizzazione degli NPC.","19. Creazione di animazioni dei personaggi in Roblox Studio.","20. Dialoghi degli NPC. Creazione di una mini-quest. Testare il gioco."],"result":"Abbiamo creato personaggi non giocanti e reso i nostri progetti più significativi aggiungendo una mini-quest."},{"title":"Modulo 6: Gioco d''avventura - Creare un sistema di valuta di gioco","lessons":["21. Creazione della valuta di gioco. Animare gli oggetti e creare una tabella di cambio valuta.","22. Implementazione dei minerali. Aggiunta di uno strumento di raccolta all''inventario.","23. Lavorare con il sistema GUI di Roblox. Creazione di un negozio in-game.","24. Lavorare sull''atmosfera. Creazione di un oggetto per lo scambio di valuta. Testare il progetto."],"result":"Abbiamo imparato a creare una valuta di gioco e un mercato. Abbiamo familiarizzato con il sistema di interfaccia grafica di Roblox."},{"title":"Modulo 7: Gioco d''avventura - Monetizzazione","lessons":["25. Distintivi. Implementazione di badge speciali che consentono ai giocatori di ottenere risultati.","26. Implementazione di pass di gioco speciale che i giocatori possono acquistare. Creazione di un animale domestico.","27. Apprendere le basi della monetizzazione di Roblox Studio. Creazione di oggetti in vendita.","28. Finalizzazione del progetto. Studio delle impostazioni del gioco. Implementazione di server privati."],"result":"Abbiamo imparato le basi del sistema di monetizzazione di Roblox e come implementarlo nei nostri progetti."},{"title":"Modulo 8: Sviluppare il nostro progetto","lessons":["29. Fondamenti di game design. Sviluppo di un''idea per il gioco.","30. Sviluppare il proprio progetto. Imparare a creare meccaniche di gioco.","31. Test finale del proprio progetto. Completamento del progetto del diploma.","32. Presentazione del progetto. Diploma."],"result":"Gli studenti hanno sviluppato i propri giochi originali. Hanno combinato diverse meccaniche e scenari di gioco."}]}'::jsonb WHERE slug = 'roblox' AND (detail_content IS NULL OR detail_content = '{}'::jsonb);

UPDATE public.courses SET detail_content = '{"longDescription":"Il corso si concentra sull''apprendimento avanzato del linguaggio di programmazione LUA così come sulla modellazione in 3D degli scenari. Il corso sviluppa il pensiero creativo e spaziale attraverso la modellazione di diversi oggetti in 3D. Gli studenti creeranno i loro giochi complessi e svilupperanno il pensiero progettuale (design thinking).","age":"10-14 anni","level":"Avanzato","duration":"32 lezioni","tags":["Script complessi","Programmazione avanzata","Meccaniche di gioco"],"topics":["Game design avanzato con modellazione 3D, creatività e programmazione","Creare giochi propri in Roblox Studio partendo dai tipi più popolari","Sviluppare il potenziale creativo dello studente","Sviluppare le competenze di programmazione avanzate","Trasformare un gruppo di studenti in un team di sviluppatori competente"],"projectExamples":[{"title":"Teamwork Puzzle"},{"title":"Tower Defence"},{"title":"Pet Simulator"}],"modules":[{"title":"Modulo 1. Fondamenti di programmazione in LUA","lessons":["1. Ripasso del lavoro con le variabili. Avvio dello sviluppo di un nuovo progetto.","2. Lavoro con le funzioni LUA. Apprendimento del debug del codice.","3. Studio dei cicli. Configurazione del teletrasporto e utilizzo del codice per cercare oggetti.","4. Consolidamento degli argomenti appresi tramite esercizi pratici."],"result":"Consolidamento delle basi di programmazione LUA e sviluppo di script autonomi."},{"title":"Modulo 2. Gioco ''Teamwork Puzzle''","lessons":["5. Inizio sviluppo di un nuovo progetto: nuova versione del popolare gioco Teamwork Puzzle.","6. Studio del ciclo for. Come ottimizzare il codice.","7. Continuiamo lo studio dei cicli. Applicazione del ciclo while nella pratica.","8. Completamento del progetto personale e pubblicazione su Roblox."],"result":"Creazione di un gioco puzzle collaborativo completo."},{"title":"Modulo 3. Gioco ''Tower Defence''","lessons":["9. Iniziamo a sviluppare un nuovo progetto nel popolare genere Tower Defence.","10. Lavoriamo con le impostazioni della telecamera in Roblox.","11. Lavoriamo con la GUI e gli eventi su LUA. Scambio di messaggi tra server e client.","12. Consolidamento e pubblicazione su Roblox."],"result":"Creazione di un Tower Defence completo con gestione telecamera e GUI."},{"title":"Modulo 4. Gioco ''Color Block''","lessons":["13. Introduzione al progetto Colour Block. Panoramica delle meccaniche base del gioco.","14. Programmazione della logica base del gioco con operatori condizionali.","15. Lavoro con colori e materiali in Roblox Studio.","16. Creazione di elementi interattivi con eventi e funzioni."],"result":"Sviluppo della scena di gioco e degli elementi base."},{"title":"Modulo 5. Gioco ''Color Block'' - Estensione delle funzionalità","lessons":["17. Sviluppo dell''interfaccia utente (GUI). Creazione e stile degli elementi.","18. Aggiunta di effetti sonori e musica. Gestione audio in Roblox Studio.","19. Script di meccaniche di gioco complesse con tecniche avanzate.","20. Rifiniture finali e pubblicazione del gioco su Roblox."],"result":"Completamento del gioco Color Block con audio e meccaniche avanzate."},{"title":"Modulo 6. Gioco ''Pet Simulator'' - Programmazione avanzata","lessons":["21. Introduzione al progetto Pet Simulator. Concept base e pianificazione.","22. Creazione di modelli base di animali. Modellazione e animazione.","23. Programmazione delle meccaniche di interazione con gli animali.","24. Sviluppo dell''economia di gioco: monete, ricompense e bonus."],"result":"Creazione delle basi di un Pet Simulator funzionante."},{"title":"Modulo 7. Gioco ''Pet Simulator'' - Nuove funzionalità","lessons":["25. Introduzione alla monetizzazione: acquisti in-game e contenuti premium.","26. Creazione di sfide e obiettivi per mantenere l''interesse dei giocatori.","27. Integrazione di elementi social: amici e condivisione degli animali.","28. Rifiniture finali e pubblicazione del gioco su Roblox."],"result":"Pet Simulator completo con monetizzazione ed elementi social."},{"title":"Modulo 8. Sviluppo del proprio progetto - Studio dell''IA","lessons":["29. Fondamenti di game design. Sviluppo dell''idea per un progetto personale.","30. Sviluppo del progetto personale. Introduzione di un assistente AI.","31. Sviluppo del progetto personale. Implementazione delle meccaniche di gioco.","32. Presentazione del progetto. Conclusione del corso."],"result":"Progetto personale originale con meccaniche creative e supporto AI."}]}'::jsonb WHERE slug = 'roblox-avanzato' AND (detail_content IS NULL OR detail_content = '{}'::jsonb);
